export function parseArgs(argv) {
  const result = { _: [] }
  let i = 0
  while (i < argv.length) {
    const arg = argv[i]
    if (arg.startsWith('-') && !arg.startsWith('--')) {
      i += 2
      continue
    }
    if (arg === '--') {
      result._.push.apply(result._, argv.slice(i + 1))
      break
    }
    if (arg.startsWith('--')) {
      const eqIndex = arg.indexOf('=')
      if (eqIndex > 2) {
        const key = arg.slice(0, eqIndex)
        const value = arg.slice(eqIndex + 1)
        result[key] = value
        i += 1
        continue
      }
      const key = arg.slice(2)
      if (i + 1 >= argv.length || !argv[i + 1].startsWith('-')) {
        result[key] = argv[++i]
      } else {
        result[key] = true
      }
    } else {
      result._.push(arg)
    }
    i += 1
  }
  return result
}

